sql:
SELECT user_name
FROM users
ORDER BY user_name;

external_knowledge:
; top 3 most active users: refers to users with the highest number of access events within the last 30 days for each access type; 
; last 30 days: calculated from the current date; 
; access category: refers to the type of access (e.g., view, download).

sql:
SELECT station_name
FROM stations
WHERE elevation = (SELECT MIN(elevation) FROM stations);
